final:
module bcd_counter (
    input clk,
    input clear,
    output reg [3:0] bcd
);
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (clear)
        bcd <= 4'b0000;
    else if (bcd == 4'b1001)
        bcd <= 4'b0000;
    else
        bcd <= bcd + 1;
end

endmodule
